const raw = $json || {};
const cluster = String(raw.cluster || '').trim().toLowerCase();
const countryRaw = String(raw.country || '').trim().toLowerCase();
const map = {
  starrocks_cn: 'cn',
  starrocks_ine: 'ine',
  starrocks_id: 'ine',
  starrocks_mex: 'mx',
  starrocks_mx: 'mx',
  starrocks_pak: 'pk',
  starrocks_pk: 'pk',
  starrocks_ph: 'ph',
  starrocks_th: 'th',
};
let country = countryRaw || map[cluster] || '';
if (!country) {
  if (cluster.includes('mex') || cluster.includes('mx')) country = 'mx';
  else if (cluster.includes('ine') || cluster.includes('indo') || cluster.includes('id')) country = 'ine';
  else if (cluster.includes('pak') || cluster.includes('pk')) country = 'pk';
  else if (cluster.includes('ph')) country = 'ph';
  else if (cluster.includes('th')) country = 'th';
  else if (cluster.includes('cn') || cluster.includes('china')) country = 'cn';
}
const requestId = String(raw.request_id || raw.queryId || raw.query_id || Date.now()).trim();
const sqlText = String(raw.sqlText || raw.sql_text || raw.originalSql || raw.original_sql || '').trim();
const sqlTextBase64 = Buffer.from(sqlText, 'utf8').toString('base64');
function collectStrings(value, seen = new Set()) {
  if (value === null || value === undefined) return [];
  if (typeof value === 'string' || typeof value === 'number') return [String(value)];
  if (typeof value !== 'object' || seen.has(value)) return [];
  seen.add(value);
  const out = [];
  if (Array.isArray(value)) {
    for (const item of value) out.push(...collectStrings(item, seen));
  } else {
    for (const item of Object.values(value)) out.push(...collectStrings(item, seen));
  }
  return out;
}
function extractIps(value) {
  return String(value || '').match(/\b(?:\d{1,3}\.){3}\d{1,3}\b/g) || [];
}
const evidence = raw.evidence || {};
const queryContext = evidence.queryContext || {};
const alert = evidence.alert || {};
const hostTexts = [
  raw.hostIp, raw.host, raw.clientIp, raw.clientHost, raw.queryHost, raw.feIp, raw.beIp,
  queryContext.hostIp, queryContext.host, queryContext.clientIp, queryContext.clientHost, queryContext.queryHost, queryContext.feIp, queryContext.beIp,
  alert.hostIp, alert.host, alert.clientIp, alert.clientHost, alert.queryHost, alert.feIp, alert.beIp,
  raw.message, raw.rawMessage, alert.message, alert.rawMessage,
  ...collectStrings(alert.hostInfo || alert.hosts || raw.hostInfo || raw.hosts || ''),
];
const hostIps = Array.from(new Set(hostTexts.flatMap(extractIps)));
const hostIp = String(raw.hostIp || raw.clientIp || raw.queryHost || hostIps[0] || '').trim();
return [{ json: { ...raw, country, request_id: requestId, sqlText, sqlTextBase64, hostIp, hostIps } }];

return [{ json: {
  success: false,
  data: [],
  candidate_count: 0,
  error: {
    code: 'INVALID_COUNTRY',
    message: 'country must be one of cn, ph, ine, mx, th, pk',
  },
}}];

const raw = $json || {};
const stdout = String(raw.stdout || '').trim();
const stderr = String(raw.stderr || '').trim();
if (Object.prototype.hasOwnProperty.call(raw, 'success') && !stdout) {
  return [{ json: raw }];
}
if (!stdout) {
  return [{ json: {
    success: false,
    data: [],
    candidate_count: 0,
    error: { code: 'EMPTY_STDOUT', message: stderr || 'empty stdout' },
  }}];
}
let parsed;
try {
  parsed = JSON.parse(stdout);
} catch (error) {
  return [{ json: {
    success: false,
    data: [],
    candidate_count: 0,
    error: { code: 'INVALID_JSON_STDOUT', message: String(error), stdout, stderr },
  }}];
}
const rows = Array.isArray(parsed.data) ? parsed.data : [];
if (!parsed.success) {
  return [{ json: { ...parsed, data: [], candidate_count: 0 } }];
}
if (!rows.length) {
  const meta = parsed.meta || {};
  const gateSkipped = (meta.ds_host_gate === 'skipped' && meta.match_info !== 'missing-alert-host-ip')
    || meta.match_info === 'alert-host-ip-not-in-ds-allowlist';
  return [{ json: {
    ...parsed,
    data: [],
    candidate_count: 0,
    ds_match_candidate_success: true,
    ds_match_candidate_country: parsed.country || '',
    ds_match_candidate_count: 0,
    dsTaskMatchOk: false,
    dsTaskMatchRequired: !gateSkipped,
    dsTaskMatchInfo: (parsed.meta && parsed.meta.match_info) || 'no-match',
  }}];
}
return rows.map((row) => ({ json: {
  ...row,
  ds_match_candidate_success: true,
  ds_match_candidate_country: parsed.country || '',
  ds_match_candidate_count: rows.length,
}}));
